#include <stdio.h>
#include <stdlib.h>

#define MOD 1000000007

int dp[4][1000001];

int tile(int k, int n) {
    if (n == 0) return 1;
    if (n < 0 || k < 1 || k > 3) return 0;
    if (dp[k][n] != -1) return dp[k][n];

    int res = 0;
    if (k == 1) {
        res = tile(1, n-2);
    } else if (k == 2) {
        res = (tile(2, n-2) + tile(1, n-1)) % MOD;
    } else if (k == 3) {
        res = (tile(3, n-3) + tile(2, n-1) + tile(1, n-2)) % MOD;
    }

    dp[k][n] = res;
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int k, n;
        scanf("%d %d", &k, &n);
        printf("%d\n", tile(k, n));
    }
    return 0;
}

