                dp[i][j] = -1;
            }
        }

        int res = 0;
        if (k == 1) {
            res = tile(1, n-2);
        } else if (k == 2) {
            res = (tile(2, n-2) + tile(1, n-1)) % 1000000007;
        } else if (k == 3) {
            res = (tile(3, n-3) + tile(2, n-1) + tile(1, n-2)) % 1000000007;
